const run = async function () {
  const BOT = '8366696724:AAHROcjGoQEn9BziD-sYdAu3ZuaolwtkgLE';
  const CHAT = '523002062';
  const http = async (o) => await this.helpers.httpRequest(Object.assign({ timeout: 30000 }, o));

  const now = new Date();
  const kst = new Date(now.getTime() + 9*60*60*1000);
  const today = `${kst.getUTCFullYear()}-${String(kst.getUTCMonth()+1).padStart(2,'0')}-${String(kst.getUTCDate()).padStart(2,'0')}`;
  const timeKst = `${String(kst.getUTCHours()).padStart(2,'0')}:${String(kst.getUTCMinutes()).padStart(2,'0')}`;
  const HOLIDAYS_2026 = ['2026-01-01','2026-02-16','2026-02-17','2026-02-18','2026-03-01','2026-03-02','2026-05-05','2026-05-24','2026-05-25','2026-06-03','2026-06-06','2026-08-15','2026-08-17','2026-09-24','2026-09-25','2026-09-26','2026-10-03','2026-10-05','2026-10-09','2026-12-25'];
  if (HOLIDAYS_2026.includes(today)) {
    return [{ json: { skipped: true, reason: 'Holiday (KRX closed)', today, timeKst } }];
  }

  const store = this.getWorkflowStaticData('global');
  if (!store.healthcheck) store.healthcheck = {};
  if (store.healthcheck.lastSentDate === today) {
    return [{ json: { skipped: true, reason: 'Already sent today', today, timeKst } }];
  }

  // () KRX        // (KRX live probe disabled) - KRX /  400    live   .
  // ,  KRX  /  .  // (KRX live probe disabled) - KRX /  400    live   .
  // ,  KRX  /  .
  let krxStatus = 'κ·ΗμôïλùΗ';
  let krxCount = 0;
  try {
    const store = this.getWorkflowStaticData('global');
    const trdDd = `${kst.getUTCFullYear()}${String(kst.getUTCMonth()+1).padStart(2,'0')}${String(kst.getUTCDate()).padStart(2,'0')}`;
    const cache = store && store.krxUniverseCache;
    const st = store && store.krxState;

    const nowMs = now.getTime();
    const circuitUntil = st && st.circuitUntil ? new Date(st.circuitUntil).getTime() : 0;
    const circuitActive = !!(circuitUntil && circuitUntil > nowMs && st && st.circuitDate === today);

    if (circuitActive) {
      krxStatus = `λ³€μ²Ζ μô€λ³±(circuitUntil=${st.circuitUntil})`;
    } else if (cache && cache.trdDd === trdDd && Array.isArray(cache.rows) && cache.rows.length) {
      krxCount = cache.rows.length;
      krxStatus = `λΚêλ΄€ OK (${krxCount}ξΑ€)`;
    } else if (cache && Array.isArray(cache.rows) && cache.rows.length) {
      krxCount = cache.rows.length;
      krxStatus = `λΚêλ΄€(λΒ€ξΖΦ) ${krxCount}ξΑ€ (trdDd=${cache.trdDd || 'unknown'})`;
    } else {
      krxStatus = 'λΚêλ΄€ λ½Üλù¨ (live probe κΙ³μô€λ³±)';
    }
  } catch (e) {
    krxStatus = 'λÉ¹μÉ€μôïλùΗ λ΄Λμ¨®: ' + String(e && e.message ? e.message : e);
  }

  const msg = `β€Ö [μ½§λäΛλ≤¥μ¹§] Autostock λäΛλΦÄλΛ³κü§ λ†ïλÉ¹\n- KST: ${today} ${timeKst}\n- KRX: ${krxStatus}`;

  try {
    await http({
      method: 'POST',
      url: 'https://api.telegram.org/bot' + BOT + '/sendMessage',
      json: true,
      body: { chat_id: CHAT, text: msg }
    });
  } catch (e) {
    return [{ json: { ok: false, error: String(e && e.message ? e.message : e), today, timeKst, krxStatus, krxCount } }];
  }

  store.healthcheck.lastSentDate = today;
  store.healthcheck.lastSentAt = now.toISOString();
  store.healthcheck.lastKrxStatus = krxStatus;
  store.healthcheck.lastKrxCount = krxCount;

  return [{ json: { ok: true, today, timeKst, krxStatus, krxCount } }];
};
return run();

const run = async function () {
  const BOT = '8366696724:AAHROcjGoQEn9BziD-sYdAu3ZuaolwtkgLE';
  const CHAT = '523002062';

  const MIN_PRICE = 1000;
  const MIN_INTRADAY_TURNOVER = 1000000000; // 10λ•Β
  const MIN_SCORE = 70;
  const RELAX_SCORE = 65;
  const MIN_DAILY_PICKS = 3;
  const MAX_INTRADAY_SENDS = 6;

  const HOLIDAYS = ['2025-01-01','2025-01-28','2025-01-29','2025-01-30','2025-03-01','2025-03-03','2025-05-05','2025-05-06','2025-06-06','2025-08-15','2025-10-03','2025-10-06','2025-10-07','2025-10-08','2025-10-09','2025-12-25','2026-01-01','2026-02-16','2026-02-17','2026-02-18','2026-03-01','2026-03-02','2026-05-05','2026-05-24','2026-05-25','2026-06-03','2026-06-06','2026-07-17','2026-08-15','2026-08-17','2026-09-24','2026-09-25','2026-09-26','2026-10-03','2026-10-05','2026-10-09','2026-12-25'];

  const DUPLICATE_WINDOW_MINUTES = 60;
  const STOP_NEW_ALERTS_HOUR = 15;
  const STOP_NEW_ALERTS_MINUTE = 20;

  const http = async (o) => await this.helpers.httpRequest(Object.assign({ timeout: 30000 }, o));

  const sma = (arr, w) => {
    const out = new Array(arr.length).fill(NaN);
    if (arr.length < w) return out;
    let sum = 0;
    for (let i=0;i<arr.length;i++){
      const v = Number(arr[i]);
      sum += (Number.isFinite(v) ? v : 0);
      if (i >= w) {
        const old = Number(arr[i-w]);
        sum -= (Number.isFinite(old) ? old : 0);
      }
      if (i >= w-1) out[i] = sum / w;
    }
    return out;
  };

  const calcAtrAbs = (highD, lowD, idx, w) => {
    const i = Math.max(0, Math.min(idx, highD.length - 1));
    const start = Math.max(0, i - w);
    const seg = [];
    for (let k=start; k<i; k++) {
      const hi = Number(highD[k]);
      const lo = Number(lowD[k]);
      if (Number.isFinite(hi) && Number.isFinite(lo)) seg.push(Math.max(0, hi - lo));
    }
    if (!seg.length) return NaN;
    const s = seg.reduce((a,b)=>a+b,0);
    return s / seg.length;
  };

  const calcQty = (accountKrw, riskPct, entry, stop) => {
    const acct = Number(accountKrw) || 0;
    const rp = Number(riskPct) || 0;
    const e = Number(entry) || 0;
    const s = Number(stop) || 0;
    const perShareRisk = e - s;
    if (!(acct > 0 && rp > 0 && e > 0 && perShareRisk > 0)) return 0;
    const riskAmt = acct * rp;
    const q = Math.floor(riskAmt / perShareRisk);
    return Math.max(0, Math.min(q, 100000));
  };

  const fetchDailyClose = async (encodedTicker) => { return []; };

  const getMarketRegime = async (store, today) => {
    // cache per day
    if (!store.regimeCache) store.regimeCache = {};
    if (store.regimeCache.date === today && store.regimeCache.riskOn !== undefined) return store.regimeCache;
    let riskOn = true;
    let ks = null;
    let kq = null;
    try {
      const [ksClose, kqClose] = await Promise.all([fetchDailyClose('%5EKS11'), fetchDailyClose('%5EKQ11')]);
      const ks20 = sma(ksClose, 20); const ks60 = sma(ksClose, 60);
      const kq20 = sma(kqClose, 20); const kq60 = sma(kqClose, 60);
      const iKs = ksClose.length - 1; const iKq = kqClose.length - 1;
      ks = (Number.isFinite(ks20[iKs]) && Number.isFinite(ks60[iKs])) ? (ks20[iKs] > ks60[iKs]) : null;
      kq = (Number.isFinite(kq20[iKq]) && Number.isFinite(kq60[iKq])) ? (kq20[iKq] > kq60[iKq]) : null;
      // κë‰ λΛë μï‰κ²‰κùΦκè³ κΣÖμôïμûà μï‰κùΫ λΕîλ³Ηκ©¥ riskOff
      if (ks === false || kq === false) riskOn = false;
    } catch (e) {
      // λ΄Λμ¨® λ΄€λ½êκäî λΕîλ≤€λù³ κ©àλΕîλßÄ λïäξΗΑ λ€³μï¥ riskOnλ€ΦκΓ€ κë†
      riskOn = true;
    }
    store.regimeCache = { date: today, riskOn, ksUp: ks, kqUp: kq, at: new Date().toISOString() };
    return store.regimeCache;
  };
  const input = (items && items[0] && items[0].json) || {};
  const forceTest = !!input.forceTest;
  const debugMode = !!input.debugMode;

  const now = new Date();
  const kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);
  const today = `${kst.getUTCFullYear()}-${String(kst.getUTCMonth() + 1).padStart(2, '0')}-${String(kst.getUTCDate()).padStart(2, '0')}`;
  const timeStrNow = String(kst.getUTCHours()).padStart(2, '0') + ':' + String(kst.getUTCMinutes()).padStart(2, '0');

  const NL = String.fromCharCode(10);
  const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  const to0 = (n) => Math.round(Number(n) || 0).toLocaleString('ko-KR');
  const pct = (r) => ((r * 100).toFixed(1) + '%');
  const normalize = (s) => String(s || '').trim();
  const getCode = (sym) => {
    const v = String(sym);
    if (v.endsWith('.KS') || v.endsWith('.KQ')) return v.slice(0, -3);
    return v;
  };

  // ===== staticData + blacklist cache =====
  const store = this.getWorkflowStaticData('global');
  if (!store.scalpingMeta) store.scalpingMeta = {};
  store.scalpingMeta.lastRunAt = now.toISOString();
  store.scalpingMeta.lastRunDate = today;
  if (!store.scalpingSent) store.scalpingSent = {};
  if (!store.weeklyRecommendations) store.weeklyRecommendations = {};
  if (!store.weeklyRecommendations[today]) store.weeklyRecommendations[today] = [];

  const bl = store.blacklist || {};
  const riskSet = new Set((bl.riskCodes || []).map(String));
  const themeFilterMode = String(bl.themeFilterMode || 'off').toLowerCase();
  const themeSet = (themeFilterMode === 'off') ? new Set() : new Set((bl.themeCodes || []).map(String));
  const riskCacheAt = bl.riskUpdatedAt || null;
  const themeCacheAt = bl.themeUpdatedAt || null;
  let excludedRisk = 0;
  let excludedTheme = 0;

  // [TEST MODE] - μ€¥λûΞ/λ΄€ξΑ³ξ≥Φ κ§¥ξ¥Äμï‰ξ≤¨ μÖîκ†àξΖΗκû® κΑ€λÜΓκß¨ μôïλùΗ
  if (forceTest) {
    const msg =
      'βöΓ [κ΄®μÉÄ λäΛλΚî μÖ¨λäΛμäΗ] λ΄€λäΛμÖ€ λ†ïλÉ¹' + NL +
      `- KST: ${today} ${timeStrNow}` + NL +
      `- riskCodes: ${(bl.riskCodes || []).length} (updatedAt=${riskCacheAt || 'null'})` + NL +
      `- themeCodes: ${(bl.themeCodes || []).length} (updatedAt=${themeCacheAt || 'null'})`;
    try {
      const res = await http({
        method: 'POST',
        url: 'https://api.telegram.org/bot' + BOT + '/sendMessage',
        json: true,
        body: { chat_id: CHAT, text: msg },
      });
      return [{ json: { testSent: true, telegramResponse: res } }];
    } catch (e) {
      return [{ json: { testSent: false, error: e?.message || String(e), stack: e?.stack } }];
    }
  }

  // ===== λûΞ/μ€¥λûΞ λ≤¥μ¹§ =====
  const d = kst.getUTCDay();
  const h = kst.getUTCHours();
  const m = kst.getUTCMinutes();

  if (!(d >= 1 && d <= 5)) return [{ json: { skipped: true, reason: 'Weekend' } }];
  if (HOLIDAYS.includes(today)) return [{ json: { skipped: true, reason: 'Holiday (KRX closed)' } }];

  if (h < 9) return [{ json: { skipped: true, reason: 'Before market open' } }];
  if (h === 9 && m < 30) return [{ json: { skipped: true, reason: 'Too early - Naver API data not ready before 09:30' } }];
  if (h >= 16) return [{ json: { skipped: true, reason: 'After market close' } }];
  if (h > STOP_NEW_ALERTS_HOUR || (h === STOP_NEW_ALERTS_HOUR && m >= STOP_NEW_ALERTS_MINUTE)) {
    return [{ json: { skipped: true, reason: 'Too close to market close' } }];
  }

  // [PERF] Queue λ†¹λ≤¥ κΑ©λßÄ: λß¹λ†³ λ΄Λμ•â λô³κΘ¨ μ¦³ 90λ¥à λù¥κ²¥κ©¥ skip
  if (store.scalpingMeta._lastFullFinish && (Date.now() - store.scalpingMeta._lastFullFinish) < 90000) {
    return [{ json: { skipped: true, reason: 'Queue backed up - fast drain' } }];
  }

  // ===== λΛëκ≥Β κΑ©λßÄ(λΒ€ξΖΦ 60κΕ³) =====
  const cutoff = now.getTime() - DUPLICATE_WINDOW_MINUTES * 60 * 1000;
  for (const t in store.scalpingSent) {
    if (store.scalpingSent[t] < cutoff) delete store.scalpingSent[t];
  }

  // ===== KRX λ€†κ΄àκ≤³λäΛ κΓ€κ™€(λïàλ†ïμôî: cache-first + μö¨μîΦ + naver fallback) =====
  // κΣ©λ†¹: KRX 400/λΑ®κ΄®λù¥ κ•†κè³ λï¨κΠΦλù¥ κ©àλΕîλßÄ λïäκè³κΓù, live μ‰ΗλΕ€λù³ λΒ€λÜ¨μôîμï‰ξ≥†(μï‰κΘ® 1μö¨ λΚêλ΄€) λ΄Λμ¨® λ΄€ κ³Λλù¥κ≤³κΓ€ μè¥κΑ±μï©κ΄àκ΄Λ.
  let rows = [];
  let krxUniverseSource = 'live';
  let krxUniverseError = null;

  const trdDd = `${kst.getUTCFullYear()}${String(kst.getUTCMonth() + 1).padStart(2, '0')}${String(kst.getUTCDate()).padStart(2, '0')}`;

  // --- simple circuit breaker in workflow staticData ---
  if (!store.krxState) store.krxState = {};
  const ks = store.krxState;
  const nowMs = now.getTime();
  const circuitUntilMs = ks.circuitUntil ? new Date(ks.circuitUntil).getTime() : 0;
  // Auto-reset circuit at first scan (09:10) to ensure fresh start
  const isFirstScan = (h === 9 && m >= 10 && m < 15);
  const circuitActive = !!(circuitUntilMs && circuitUntilMs > nowMs && ks.circuitDate === today && !isFirstScan);
  if (isFirstScan && ks.circuitUntil) {
    // Reset circuit breaker at first scan of the day
    delete ks.circuitUntil;
    delete ks.circuitDate;
  }

  const openCircuit = (reason) => {
    const until = new Date(nowMs + 15 * 60 * 1000).toISOString();
    ks.circuitDate = today;
    ks.circuitUntil = until;
    ks.lastFailAt = new Date(nowMs).toISOString();
    ks.lastFailReason = String(reason || 'unknown');
  };

  // --- cache-first: if we already have today's universe, don't hit KRX again ---
  // --- Naver-based universe loading (replaces KRX API) ---
  if (store.krxUniverseCache && store.krxUniverseCache.trdDd === trdDd && Array.isArray(store.krxUniverseCache.rows) && store.krxUniverseCache.rows.length) {
    rows = store.krxUniverseCache.rows;
    krxUniverseSource = 'cache';
  } else {
    // Fetch full stock list from Naver Finance (all KOSPI + KOSDAQ stocks)
    krxUniverseSource = 'naver';

    const fetchText = async (url) => {
      const raw = await http({
        method: 'GET',
        url,
        headers: { 
          'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36', 
          'Referer': 'https://finance.naver.com/',
          'Accept': 'text/html',
          'Accept-Charset': 'utf-8'
        },
        json: false,
        encoding: 'utf8'
      });
      if (Buffer.isBuffer(raw)) return raw.toString('utf8');
      return String(raw ?? '');
    };

    const extractCodeNamePairs = (html) => {
      const out = [];
      const re = new RegExp('/item/main\\.naver\\?code=(\\d{6})[^>]*>([^<]{1,60})<', 'g');
      let m;
      while ((m = re.exec(html))) {
        out.push([m[1], String(m[2] || '').trim()]);
      }
      return out;
    };

    const codeSet = new Set();
    const naverRows = [];
    const MAX_PAGES = 50; // Fetch all pages to get complete list

    const fetchAllFromMarket = async (sosok, mktNm) => {
      for (let p = 1; p <= MAX_PAGES; p++) {
        try {
          const url = `https://finance.naver.com/sise/sise_market_sum.naver?sosok=${sosok}&page=${p}`;
          const html = await fetchText(url);
          const pairs = extractCodeNamePairs(html);

          if (!pairs || pairs.length === 0) {
            break; // No more pages
          }

          let newStocks = 0;
          for (const [c, nm] of pairs) {
            if (!c || codeSet.has(c)) continue;
            codeSet.add(c);
            naverRows.push({
              ISU_SRT_CD: c,
              ISU_ABBRV: nm || c,
              ISU_NM: nm || c,
              MKT_NM: mktNm,
              TDD_CLSPRC: String(MIN_PRICE),
              ACC_TRDVAL: String(MIN_INTRADAY_TURNOVER),
            });
            newStocks++;
          }

          if (newStocks === 0) {
            break; // No new stocks, end of list
          }

          await new Promise((r) => setTimeout(r, 100 + Math.floor(Math.random() * 50)));
        } catch (e) {
          // Page error, continue to next
          await new Promise((r) => setTimeout(r, 500));
        }
      }
    };

    try {
      await fetchAllFromMarket(0, 'KOSPI');
      await fetchAllFromMarket(1, 'KOSDAQ');
      rows = naverRows;

      if (rows.length > 0) {
        krxUniverseSource = 'naver';
        // Cache the full universe for the day
        store.krxUniverseCache = {
          trdDd,
          fetchedAt: new Date(nowMs).toISOString(),
          source: 'naver',
          rows: rows.slice(0, 4500).map((x) => ({
            ISU_SRT_CD: String(x?.ISU_SRT_CD || ''),
            ISU_ABBRV: String(x?.ISU_ABBRV || ''),
            ISU_NM: String(x?.ISU_NM || ''),
            MKT_NM: String(x?.MKT_NM || ''),
            TDD_CLSPRC: String(x?.TDD_CLSPRC || '0'),
            ACC_TRDVAL: String(x?.ACC_TRDVAL || '0'),
          })),
        };
      } else {
        krxUniverseError = 'Naver returned 0 rows';
      }
    } catch (e) {
      krxUniverseError = String(e?.message || e);
    }
  }


  const NAME = {};
  const ALL_TICKERS = [];
  const SEEN_CODES = new Set();

  for (const row of rows) {
    const rc = normalize(String(row?.ISU_SRT_CD || ''));
    const nm = String(row?.ISU_ABBRV || row?.ISU_NM || '').trim();
    const mkt = String(row?.MKT_NM || '').toLowerCase();

    if (!rc || !nm) continue;
    if (SEEN_CODES.has(rc)) continue;
    SEEN_CODES.add(rc);

    if (mkt.includes('konex') || mkt.includes('λΫîκ³ΞλäΛ')) continue;

    // λ³†λ†€ λ†€λôΗ: κΠ§λäΛμ¹§/μÖ¨κßà
    if (riskSet.has(rc)) { excludedRisk++; continue; }
    if (themeSet.has(rc)) { excludedTheme++; continue; }

    const price = Number(String(row?.TDD_CLSPRC || '0').replace(/,/g, ''));
    const turnover = Number(String(row?.ACC_TRDVAL || '0').replace(/,/g, ''));

    if (price < MIN_PRICE) continue;
    if (turnover < MIN_INTRADAY_TURNOVER) continue;

    NAME[rc] = nm;

    let suffix = '.KS';
    if (mkt.includes('kosdaq') || mkt.includes('λΫîλäΛκ΄Ξ')) suffix = '.KQ';
    ALL_TICKERS.push(rc + suffix);
  }

  if (ALL_TICKERS.length === 0) {
    // λΕîλ≤€ λΔÖκΣ©λù¥ 0ξΑ€λ½§κè³ 'λïàκ²¥ λï¨κΠΦ'λùÄ μï‰κΘ® 1μö¨ ξΦ≠ κ≥¥κ²¥ξΗΑ (λäΛμ¨Η κΑ©λßÄ)
    if (!store.scalpingAlerts) store.scalpingAlerts = {};
    if (store.scalpingAlerts.universeEmptyDate !== today) {
      const msg =
        'βö†οΗè [κ΄®μÉÄ] λΕîλ≤€ μ¦³κ≥¥ λÉùλ³± κΕàξΑÄ(λ€†κ΄àκ≤³λäΛ 0ξΑ€)' + NL +
        `- KST: ${today} ${timeStrNow}` + NL +
        `- KRX source: ${krxUniverseSource}` + NL +
        `- KRX error: ${krxUniverseError || 'none'}` + NL +
        `- circuit: ${circuitActive ? 'YES (until ' + ks.circuitUntil + ')' : 'no'}` + NL +
        `- rows loaded: ${rows.length}` + NL +
        `- λ†€λôΗ(κΠ§λäΛμ¹§): ${excludedRisk}` + NL +
        `- λ†€λôΗ(μÖ¨κßà): ${excludedTheme}` + NL +
        `- riskCacheAt: ${riskCacheAt || 'null'}` + NL +
        `- themeCacheAt: ${themeCacheAt || 'null'}`;
      try { await http({ method: 'POST', url: 'https://api.telegram.org/bot' + BOT + '/sendMessage', json: true, body: { chat_id: CHAT, text: msg } }); } catch (e) {}
      store.scalpingAlerts.universeEmptyDate = today;
    }
    if (debugMode) {
      const msg =
        'πüîç [κ΄®μÉÄ κîîκ≤³ξΖΗ] λ€†κ΄àκ≤³λäΛ 0ξΑ€' + NL +
        `- λ†€λôΗ(κΠ§λäΛμ¹§): ${excludedRisk}` + NL +
        `- λ†€λôΗ(μÖ¨κßà): ${excludedTheme}` + NL +
        `- riskCacheAt: ${riskCacheAt || 'null'}` + NL +
        `- themeCacheAt: ${themeCacheAt || 'null'}` + NL +
        `- KST: ${today} ${timeStrNow}`;
      try { await http({ method: 'POST', url: 'https://api.telegram.org/bot' + BOT + '/sendMessage', json: true, body: { chat_id: CHAT, text: msg } }); } catch (e) {}
    }
    return [{ json: { ok: false, reason: 'universe_empty', excludedRisk, excludedTheme, riskCacheAt, themeCacheAt } }];
  }

  // ===== Technical Indicators =====

  const rsi14 = (close) => {
    const p = 14;
    const out = new Array(close.length).fill(NaN);
    if (close.length < p + 1) return out;
    const up = [];
    const dn = [];
    for (let i = 1; i < close.length; i++) {
      const d = close[i] - close[i - 1];
      up.push(Math.max(d, 0));
      dn.push(Math.max(-d, 0));
    }
    const smaN = (a, w) => {
      const o = new Array(a.length).fill(NaN);
      if (a.length < w) return o;
      let sum = 0;
      for (let i = 0; i < a.length; i++) {
        sum += a[i];
        if (i >= w) sum -= a[i - w];
        if (i >= w - 1) o[i] = sum / w;
      }
      return o;
    };
    const au = smaN([0].concat(up), p);
    const ad = smaN([0].concat(dn), p);
    for (let i = 0; i < close.length; i++) {
      if (!Number.isFinite(au[i]) || !Number.isFinite(ad[i])) continue;
      const rs = ad[i] === 0 ? 999 : au[i] / ad[i];
      out[i] = 100 - 100 / (1 + rs);
    }
    return out;
  };

  // ===== EMA calculation for MACD =====
  const ema = (arr, period) => {
    const out = new Array(arr.length).fill(NaN);
    if (arr.length < period) return out;
    const k = 2 / (period + 1);
    let emaVal = arr.slice(0, period).reduce((a, b) => a + Number(b || 0), 0) / period;
    out[period - 1] = emaVal;
    for (let i = period; i < arr.length; i++) {
      const val = Number(arr[i]);
      if (Number.isFinite(val)) {
        emaVal = val * k + emaVal * (1 - k);
        out[i] = emaVal;
      } else {
        out[i] = emaVal;
      }
    }
    return out;
  };

  // ===== MACD calculation =====
